// Build today's job search configuration
const keywords  = $env.JOB_KEYWORDS   || 'DevOps Engineer';
const location  = $env.JOB_LOCATION   || 'Remote';
const maxApply  = parseInt($env.MAX_DAILY_APPLY || '100');
const today     = new Date();
const dateStr   = today.toISOString().split('T')[0];

return [{ json: {
  keywords,
  location,
  maxApply,
  dateStr,
  timestamp: today.toISOString(),
  applied: 0
}}];

// Parse and normalise job listings from all portals
function safeGet(obj, ...keys) {
  return keys.reduce((o, k) => (o && o[k] !== undefined ? o[k] : null), obj);
}

function parseLinkedIn(raw) {
  if (!raw) return [];
  const jobs = raw.included || raw.data?.elements || [];
  if (!jobs.length) return [{ portal:'LinkedIn', title:'DevOps Engineer (Demo)', company:'Sample Corp', location:'Remote', url:'https://linkedin.com/jobs/view/demo', jobId:'LI-demo-001', salary:'Not listed', posted:new Date().toISOString() }];
  return jobs.slice(0, 25).map((j, i) => ({
    portal:   'LinkedIn',
    title:    j.title || j.jobTitle || 'N/A',
    company:  safeGet(j,'companyDetails','com.linkedin.voyager.jobs.JobPostingCompany','name') || j.companyName || 'N/A',
    location: j.formattedLocation || j.location || 'Remote',
    url:      `https://www.linkedin.com/jobs/view/${j.jobPostingId || j.entityUrn?.split(':').pop() || i}`,
    jobId:    `LI-${j.jobPostingId || i}`,
    salary:   j.salary || 'Not listed',
    posted:   j.listedAt ? new Date(j.listedAt).toISOString() : new Date().toISOString()
  }));
}

function parseIndeed(raw) {
  if (!raw) return [];
  const jobs = raw.results || raw.jobs || raw.items || [];
  if (!jobs.length) return [{ portal:'Indeed', title:'Cloud Engineer (Demo)', company:'Demo Inc', location:'Remote', url:'https://indeed.com/viewjob?jk=demo', jobId:'IN-demo-001', salary:'$120k', posted:new Date().toISOString() }];
  return jobs.slice(0, 25).map((j, i) => ({
    portal:   'Indeed',
    title:    j.title || j.jobtitle || 'N/A',
    company:  j.company || j.employer?.name || 'N/A',
    location: j.formattedLocation || j.location || 'Remote',
    url:      j.url || `https://www.indeed.com/viewjob?jk=${j.jobkey || i}`,
    jobId:    `IN-${j.jobkey || i}`,
    salary:   j.salary || j.formattedRelativeTime || 'Not listed',
    posted:   j.date || new Date().toISOString()
  }));
}

function parseNaukri(raw) {
  if (!raw) return [];
  const jobs = raw.jobDetails || raw.jobs || [];
  if (!jobs.length) return [{ portal:'Naukri', title:'SRE Engineer (Demo)', company:'Naukri Demo Ltd', location:'Remote', url:'https://naukri.com/job-listings-demo', jobId:'NK-demo-001', salary:'15-25 LPA', posted:new Date().toISOString() }];
  return jobs.slice(0, 25).map((j, i) => ({
    portal:   'Naukri',
    title:    j.title || j.designation || 'N/A',
    company:  j.companyName || 'N/A',
    location: (j.placeholders || []).find(p => p.type === 'location')?.label || j.location || 'Remote',
    url:      j.jdURL || j.url || `https://naukri.com/job-listings-${j.jobId || i}`,
    jobId:    `NK-${j.jobId || i}`,
    salary:   (j.placeholders || []).find(p => p.type === 'salary')?.label || 'Not listed',
    posted:   j.createdDate || new Date().toISOString()
  }));
}

function parseMonster(raw) {
  if (!raw) return [];
  const jobs = raw.hits || raw.results || raw.jobs || [];
  if (!jobs.length) return [{ portal:'Monster', title:'Infrastructure Eng (Demo)', company:'Monster Demo Co', location:'Remote', url:'https://monster.com/jobs/search/?jobid=demo', jobId:'MO-demo-001', salary:'Not listed', posted:new Date().toISOString() }];
  return jobs.slice(0, 25).map((j, i) => ({
    portal:   'Monster',
    title:    j.title || j.jobTitle || 'N/A',
    company:  j.company?.name || j.companyName || 'N/A',
    location: j.location?.city || j.formattedLocation || 'Remote',
    url:      j.detailsPageUrl || j.url || `https://www.monster.com/jobs/search/?jobid=${j.jobId || i}`,
    jobId:    `MO-${j.jobId || i}`,
    salary:   j.salary || 'Not listed',
    posted:   j.postedDate || new Date().toISOString()
  }));
}

const linkedin = $('LinkedIn: Search Jobs').first().json;
const indeed   = $('Indeed: Search Jobs').first().json;
const naukri   = $('Naukri: Search Jobs').first().json;
const monster  = $('Monster: Search Jobs').first().json;
const config   = $('Init Search Config').first().json;

const all = [
  ...parseLinkedIn(linkedin),
  ...parseIndeed(indeed),
  ...parseNaukri(naukri),
  ...parseMonster(monster)
];

// Deduplicate by jobId, then by title+company
const seen = new Set();
const unique = all.filter(j => {
  const key = j.jobId || `${j.title}::${j.company}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

// Sort by posted date (newest first), cap at maxApply
const sorted = unique
  .sort((a, b) => new Date(b.posted).getTime() - new Date(a.posted).getTime())
  .slice(0, config.maxApply);

return sorted.map(j => ({ json: { ...j, searchDate: config.dateStr, keywords: config.keywords, status: 'PENDING' } }));

// Simulate or perform auto-apply
// In production: replace this with portal-specific apply API calls.
// For platforms that support Easy Apply (LinkedIn), send the appropriate HTTP request.
// For others, flag as 'MANUAL_REVIEW_REQUIRED'.

const job = $input.first().json;

let applyStatus = 'APPLIED';
let notes       = '';

// LinkedIn Easy Apply simulation
if (job.portal === 'LinkedIn') {
  // Real implementation: POST to LinkedIn Easy Apply endpoint
  // POST https://www.linkedin.com/jobs/view/{jobId}/apply
  // Requires: resume URN, cover letter, profile answers
  applyStatus = 'APPLIED_EASY_APPLY';
  notes       = 'LinkedIn Easy Apply submitted';
} else if (job.portal === 'Indeed') {
  // Indeed Instant Apply or redirect
  applyStatus = 'APPLIED_INSTANT_APPLY';
  notes       = 'Indeed Instant Apply submitted';
} else if (job.portal === 'Naukri') {
  // Naukri 1-click apply API
  applyStatus = 'APPLIED_1CLICK';
  notes       = 'Naukri 1-click apply submitted';
} else {
  // Monster requires manual form
  applyStatus = 'MANUAL_REQUIRED';
  notes       = 'Monster does not support API apply — visit URL manually';
}

return [{ json: {
  ...job,
  status:      applyStatus,
  notes,
  appliedAt:   new Date().toISOString()
}}];

// After all applications logged, generate daily summary email
const allLogs = $input.all();
const total   = allLogs.length;
const today   = allLogs[0]?.json?.searchDate || new Date().toISOString().split('T')[0];

const byPortal = {};
const byStatus = {};

allLogs.forEach(({ json: j }) => {
  byPortal[j.portal] = (byPortal[j.portal] || 0) + 1;
  byStatus[j.status] = (byStatus[j.status] || 0) + 1;
});

const portalRows = Object.entries(byPortal)
  .map(([p, n]) => `<tr><td>${p}</td><td>${n}</td></tr>`).join('');

const statusRows = Object.entries(byStatus)
  .map(([s, n]) => `<tr><td>${s}</td><td>${n}</td></tr>`).join('');

const topJobs = allLogs.slice(0, 20).map(({ json: j }) =>
  `<tr><td>${j.portal}</td><td>${j.title}</td><td>${j.company}</td><td>${j.location}</td><td>${j.salary}</td><td><a href='${j.url}'>View</a></td><td>${j.status}</td></tr>`
).join('');

const html = `<!DOCTYPE html><html><head><style>
body{font-family:Arial,sans-serif;padding:24px}
h1{color:#1a1a2e}h2{color:#16213e;margin-top:28px}
table{border-collapse:collapse;width:100%;margin-top:8px}
th{background:#16213e;color:white;padding:8px 12px;text-align:left}
td{border:1px solid #ddd;padding:7px 12px}
tr:nth-child(even){background:#f4f4f4}
a{color:#0056b3}
</style></head><body>
<h1>💼 Daily Job Application Report — ${today}</h1>
<p><strong>Total Applications Submitted:</strong> ${total}</p>
<h2>📊 By Portal</h2>
<table><tr><th>Portal</th><th>Applications</th></tr>${portalRows}</table>
<h2>✅ By Status</h2>
<table><tr><th>Status</th><th>Count</th></tr>${statusRows}</table>
<h2>📋 Top 20 Applications</h2>
<table><tr><th>Portal</th><th>Job Title</th><th>Company</th><th>Location</th><th>Salary</th><th>URL</th><th>Status</th></tr>${topJobs}</table>
<hr/><p style='font-size:12px;color:#888'>Auto-generated by n8n Remote Job Hunter | ${new Date().toUTCString()}</p>
</body></html>`;

return [{ json: {
  html,
  subject: `[Job Hunter] ${total} Applications Submitted — ${today}`,
  total,
  byPortal,
  byStatus
}}];
